241	func updateAffinityRules(deployment *appsv1.Deployment, trustManager *v1alpha1.TrustManager) error {
242		if trustManager.Spec.TrustManagerConfig.Affinity == nil {
243			return nil
244		}
245		if err := common.ValidateAffinityRules(trustManager.Spec.TrustManagerConfig.Affinity, trustManagerConfigFieldPath); err != nil {
246			return err
247		}
248		deployment.Spec.Template.Spec.Affinity = trustManager.Spec.TrustManagerConfig.Affinity
249		return nil
250	}
