252	func updatePodTolerations(deployment *appsv1.Deployment, trustManager *v1alpha1.TrustManager) error {
253		if trustManager.Spec.TrustManagerConfig.Tolerations == nil {
254			return nil
255		}
256		if err := common.ValidateTolerationsConfig(trustManager.Spec.TrustManagerConfig.Tolerations, trustManagerConfigFieldPath); err != nil {
257			return err
258		}
259		deployment.Spec.Template.Spec.Tolerations = trustManager.Spec.TrustManagerConfig.Tolerations
260		return nil
261	}
262	
263	func updateNodeSelector(deployment *appsv1.Deployment, trustManager *v1alpha1.TrustManager) error {
264		if trustManager.Spec.TrustManagerConfig.NodeSelector == nil {
265			return nil
266		}
267		if err := common.ValidateNodeSelectorConfig(trustManager.Spec.TrustManagerConfig.NodeSelector, trustManagerConfigFieldPath); err != nil {
268			return err
269		}
270		if deployment.Spec.Template.Spec.NodeSelector == nil {
271			deployment.Spec.Template.Spec.NodeSelector = make(map[string]string)
272		}
273		// Merge user-specified node selectors with any default selectors from the manifest.
274		// User-specified selectors take precedence.
275		for k, v := range trustManager.Spec.TrustManagerConfig.NodeSelector {
276			deployment.Spec.Template.Spec.NodeSelector[k] = v
277		}
278		return nil
279	}
