296	// deploymentModified compares only the fields we manage via SSA.
297	// For the readiness probe, only the fields explicitly set in our bindata are
298	// compared to avoid false positives from API-server-defaulted probe scalars
299	// (TimeoutSeconds, SuccessThreshold, FailureThreshold).
300	func deploymentModified(desired, existing *appsv1.Deployment) bool {
301		if managedMetadataModified(desired, existing) {
302			return true
303		}
304	
305		if !ptr.Equal(desired.Spec.Replicas, existing.Spec.Replicas) ||
306			!reflect.DeepEqual(desired.Spec.Selector, existing.Spec.Selector) {
307			return true
308		}
309	
310		if !maps.Equal(desired.Spec.Template.Labels, existing.Spec.Template.Labels) ||
311			!maps.Equal(desired.Spec.Template.Annotations, existing.Spec.Template.Annotations) {
312			return true
313		}
314	
315		desiredPodSpec := desired.Spec.Template.Spec
316		existingPodSpec := existing.Spec.Template.Spec
317	
318		if desiredPodSpec.ServiceAccountName != existingPodSpec.ServiceAccountName ||
319			!maps.Equal(desiredPodSpec.NodeSelector, existingPodSpec.NodeSelector) ||
320			!reflect.DeepEqual(desiredPodSpec.Volumes, existingPodSpec.Volumes) ||
321			!reflect.DeepEqual(desiredPodSpec.Affinity, existingPodSpec.Affinity) ||
322			!reflect.DeepEqual(desiredPodSpec.Tolerations, existingPodSpec.Tolerations) {
323			return true
324		}
325	
326		if len(desiredPodSpec.Containers) != len(existingPodSpec.Containers) {
327			return true
328		}
329	
330		for i := range desiredPodSpec.Containers {
331			if containerModified(&desiredPodSpec.Containers[i], &existingPodSpec.Containers[i]) {
332				return true
333			}
334		}
335	
336		return false
337	}
338	
339	func containerModified(desired, existing *corev1.Container) bool {
340		if desired.Name != existing.Name ||
341			desired.Image != existing.Image ||
342			desired.ImagePullPolicy != existing.ImagePullPolicy {
343			return true
344		}
345	
346		if !slices.Equal(desired.Args, existing.Args) ||
347			!reflect.DeepEqual(desired.Resources, existing.Resources) ||
348			!reflect.DeepEqual(desired.SecurityContext, existing.SecurityContext) ||
349			!reflect.DeepEqual(desired.VolumeMounts, existing.VolumeMounts) {
350			return true
351		}
352	
353		if !containerPortsMatch(desired.Ports, existing.Ports) {
354			return true
355		}
356	
357		if readinessProbeModified(desired.ReadinessProbe, existing.ReadinessProbe) {
358			return true
359		}
360	
361		return false
362	}
363	
364	func containerPortsMatch(desired, existing []corev1.ContainerPort) bool {
365		if len(desired) != len(existing) {
366			return false
367		}
368		for _, dp := range desired {
369			matched := false
370			for _, ep := range existing {
371				if dp.ContainerPort == ep.ContainerPort && dp.Name == ep.Name {
372					matched = true
373					break
374				}
375			}
376			if !matched {
377				return false
378			}
379		}
380		return true
381	}
382	
383	// readinessProbeModified compares only the probe fields we explicitly set in
384	// bindata (HTTPGet, InitialDelaySeconds, PeriodSeconds), avoiding
385	// API-server-defaulted int32 fields like TimeoutSeconds and FailureThreshold.
386	func readinessProbeModified(desired, existing *corev1.Probe) bool {
387		if desired == nil && existing == nil {
388			return false
389		}
390		if desired == nil || existing == nil {
391			return true
392		}
393		if desired.InitialDelaySeconds != existing.InitialDelaySeconds ||
394			desired.PeriodSeconds != existing.PeriodSeconds {
395			return true
396		}
397		if desired.HTTPGet != nil && existing.HTTPGet != nil {
398			if desired.HTTPGet.Path != existing.HTTPGet.Path ||
399				desired.HTTPGet.Port != existing.HTTPGet.Port {
400				return true
401			}
402		} else if desired.HTTPGet != existing.HTTPGet {
403			return true
404		}
405		return false
406	}
