### File 3: `pkg/controller/trustmanager/proxy.go` (new file)

This contains the `updateProxyEnv` mutation function that reads proxy settings from the cluster Proxy object via the informer's lister and injects `HTTP_PROXY`, `HTTPS_PROXY`, and `NO_PROXY` env vars into the trust-manager deployment:

```go
package trustmanager

import (
	appsv1 "k8s.io/api/apps/v1"
	corev1 "k8s.io/api/core/v1"
)

// updateProxyEnv reads cluster-wide proxy settings from the Proxy informer
// and sets HTTP_PROXY, HTTPS_PROXY, and NO_PROXY environment variables on
// the trust-manager container. Caller must check proxyInformer.Applicable()
// before calling.
func (r *Reconciler) updateProxyEnv(deployment *appsv1.Deployment) error {
	proxy, err := (*r.proxyInformer.InformerFactory).Config().V1().Proxies().Lister().Get("cluster")
	if err != nil {
		return err
	}

	proxyEnvVars := []corev1.EnvVar{
		{Name: "HTTP_PROXY", Value: proxy.Status.HTTPProxy},
		{Name: "HTTPS_PROXY", Value: proxy.Status.HTTPSProxy},
		{Name: "NO_PROXY", Value: proxy.Status.NoProxy},
	}

	for i, container := range deployment.Spec.Template.Spec.Containers {
		if container.Name == trustManagerContainerName {
			deployment.Spec.Template.Spec.Containers[i].Env = mergeProxyEnvVars(
				deployment.Spec.Template.Spec.Containers[i].Env,
				proxyEnvVars,
			)
			break
		}
	}

	return nil
}

// mergeProxyEnvVars merges proxy environment variables into the existing
// env slice. Proxy vars override any existing entries with the same name.
func mergeProxyEnvVars(existing, proxyVars []corev1.EnvVar) []corev1.EnvVar {
	proxyKeys := make(map[string]corev1.EnvVar, len(proxyVars))
	for _, e := range proxyVars {
		if e.Value != "" {
			proxyKeys[e.Name] = e
		}
	}

	if len(proxyKeys) == 0 {
		return existing
	}

	var result []corev1.EnvVar
	seen := make(map[string]bool, len(proxyKeys))
	for _, e := range existing {
		if replacement, ok := proxyKeys[e.Name]; ok {
			result = append(result, replacement)
			seen[e.Name] = true
		} else {
			result = append(result, e)
		}
	}
	for _, e := range proxyVars {
		if e.Value != "" && !seen[e.Name] {
			result = append(result, e)
		}
	}
	return result
}
